```javascript
function solve(nums) {
    const n = nums.length;
    if (n === 0) return 0;
    const max_num = 1000000;
    const spf = new Array(max_num + 1).fill(0);
    for (let i = 2; i <= max_num; i++) {
        if (spf[i] === 0) {
            spf[i] = i;
            for (let j = i * 2; j <= max_num; j += i) {
                if (spf[j] === 0) {
                    spf[j] = i;
                }
            }
        }
    }
    const primeToIndices = new Map();
    for (let i = 0; i < n; i++) {
        const num = nums[i];
        if (num === 1) continue;
        const factors = new Set();
        let x = num;
        while (x > 1) {
            const p = spf[x];
            factors.add(p);
            while (x % p === 0) {
                x /= p;
            }
        }
        for (const p of factors) {
            if (!primeToIndices.has(p)) {
                primeToIndices.set(p, []);
            }
            primeToIndices.get(p).push(i);
        }
    }
    const visited = new Array(n).fill(false);
    const queue = [0];
    visited[0] = true;
    let steps = 0;
    while (queue.length > 0) {
        const levelSize = queue.length;
        for (let i = 0; i < levelSize; i++) {
            const current = queue.shift();
            if (current === n - 1) {
                return steps;
            }
            if (current > 0 && !visited[current - 1]) {
                visited[current - 1] = true;
                queue.push(current - 1);
            }
            if (current < n - 1 && !visited[current + 1]) {
                visited[current + 1] = true;
                queue.push(current + 1);
            }
            const num = nums[current];
            if (num > 1 && spf[num] === num) {
                if (primeToIndices.has(num)) {
                    const indices = primeToIndices.get(num);
                    for (const j of indices) {
                        if (j !== current && !visited[j]) {
                            visited[j] = true;
                            queue.push(j);
                        }
                    }
                }
            }
        }
        steps++;
    }
    return -1;
}
